    for item in items {
        if item == target {
            count += 1;
        }
    }
    return count;
}

with entry {
    words: list[str] = ["jac", "graph", "walker", "jac", "node", "jac"];
    print(count_matches(words, "jac"));
    print(count_matches(words, "edge"));
}","complexity":"simple","prompt":"Write a complete Jac utility program that counts how many times a target string appears in a list and demonstrates it with two target values."},{"code":"can normalize_path(path: str) -> str {
    cleaned: str = "";
    last_slash: bool = false;
    for ch in path {
        if ch == "/" {
            if !last_slash {
                cleaned += ch;
            }
            last_slash = true;
        } else {
            cleaned += ch;
            last_slash = false;
        }
    }
    if len(cleaned) > 1 and cleaned[-1] == "/" {
        cleaned = cleaned[:-1];
    }
    return cleaned;
}

can build_route(base: str, resource: str, ident: int) -> str {
    return normalize_path(base + "/" + resource + "/" + str(ident));
}

with entry {
    print(build_route("/api//v1/", "users", 42));
    print(build_route("/service///", "health", 1));
}","complexity":"medium","prompt":"Write a complete Jac program for a small web utility that normalizes duplicate slashes in URL paths and builds resource routes from a base path, resource name, and numeric identifier."},{"code":"can top_scores(scores: dict[str, int], limit: int) -> list[str] {
    selected: list[str] = [];
    used: dict[str, bool] = {};
    while len(selected) < limit and len(selected) < len(scores) {
        best_name: str = "";
        best_score: int = -1;
        for name in scores {
            if !(name in used) and scores[name] > best_score {
                best_name = name;
                best_score = scores[name];
            }
        }
        if best_name == "" {
            break;
        }
        selected.append(best_name);
        used[best_name] = true;
    }
    return selected;
}

with entry {
    scores: dict[str, int] = {"ana": 91, "bo": 77, "cy": 95, "di": 88};
    winners: list[str] = top_scores(scores, 3);
    for name in winners {
        print(name);
    }
}","complexity":"medium","prompt":"Write a complete Jac data-processing program that stores names and scores in a dictionary, selects the top N names by score without using sorting, and prints the selected names."},{"code":"can shortest_distances(graph: dict[str, dict[str, int]], start: str) -> dict[str, int] {
    distances: dict[str, int] = {};
    visited: dict[str, bool] = {};
    for node in graph {
        distances[node] = 1000000;
        visited[node] = false;
    }
    distances[start] = 0;
    while true {
        current: str = "";
        best: int = 1000000;
        for node in graph {
            if !visited[node] and distances[node] < best {
                current = node;
                best = distances[node];
            }
        }
        if current == "" {
            break;
        }
        visited[current] = true;
        for neighbor in graph[current] {
            candidate: int = distances[current] + graph[current][neighbor];
            if candidate < distances[neighbor] {
                distances[neighbor] = candidate;
            }
        }
    }
    return distances;
}

